 26→// Note: CycleState uses a sync.Map to back the storage, because it is thread safe. It's aimed to optimize for the "write once and read many times" scenarios.
 27→// It is the recommended pattern used in all in-tree plugins - plugin-specific state is written once in PreFilter/PreScore and afterward read many times in Filter/Score.
 28→type CycleState struct {
 29→	// storage is keyed with StateKey, and valued with StateData.
 30→	storage sync.Map
 31→	// if recordPluginMetrics is true, metrics.PluginExecutionDuration will be recorded for this cycle.
 32→	recordPluginMetrics bool
 33→	// skipFilterPlugins are plugins that will be skipped in the Filter extension point.
 34→	skipFilterPlugins sets.Set[string]
 35→	// skipScorePlugins are plugins that will be skipped in the Score extension point.
 36→	skipScorePlugins sets.Set[string]
 37→	// skipPreBindPlugins are plugins that will be skipped in the PreBind extension point.
 38→	skipPreBindPlugins sets.Set[string]
 39→	// GetParallelPreBindPlugins returns plugins that can be run in parallel with other plugins
 40→	// in the PreBind extension point.
 41→	parallelPreBindPlugins sets.Set[string]
 42→}
 43→
 44→// NewCycleState initializes a new CycleState and returns its pointer.
 45→func NewCycleState() *CycleState {
 46→	return &CycleState{}
 47→}
 48→
 49→// ShouldRecordPluginMetrics returns whether metrics.PluginExecutionDuration metrics should be recorded.
 50→func (c *CycleState) ShouldRecordPluginMetrics() bool {
 51→	if c == nil {
 52→		return false
 53→	}
 54→	return c.recordPluginMetrics
 55→}
 56→
 57→// SetRecordPluginMetrics sets recordPluginMetrics to the given value.
 58→func (c *CycleState) SetRecordPluginMetrics(flag bool) {
 59→	if c == nil {
 60→		return
 61→	}
 62→	c.recordPluginMetrics = flag
 63→}
 64→
 65→func (c *CycleState) SetSkipFilterPlugins(plugins sets.Set[string]) {
 66→	c.skipFilterPlugins = plugins
 67→}
 68→
 69→func (c *CycleState) GetSkipFilterPlugins() sets.Set[string] {
 70→	return c.skipFilterPlugins
 71→}
 72→
 73→func (c *CycleState) SetSkipScorePlugins(plugins sets.Set[string]) {
 74→	c.skipScorePlugins = plugins
 75→}
 76→
 77→func (c *CycleState) GetSkipScorePlugins() sets.Set[string] {
 78→	return c.skipScorePlugins
 79→}
 80→
 81→func (c *CycleState) SetSkipPreBindPlugins(plugins sets.Set[string]) {
 82→	c.skipPreBindPlugins = plugins
 83→}
 84→
 85→func (c *CycleState) GetSkipPreBindPlugins() sets.Set[string] {
 86→	return c.skipPreBindPlugins
 87→}
 88→
 89→func (c *CycleState) SetParallelPreBindPlugins(plugins sets.Set[string]) {
 90→	c.parallelPreBindPlugins = plugins
 91→}
 92→
 93→func (c *CycleState) GetParallelPreBindPlugins() sets.Set[string] {
 94→	return c.parallelPreBindPlugins
 95→}
 96→
 97→// Clone creates a copy of CycleState and returns its pointer. Clone returns
 98→// nil if the context being cloned is nil.
 99→func (c *CycleState) Clone() fwk.CycleState {
100→	if c == nil {
101→		return nil
102→	}
103→	copy := NewCycleState()
104→	// Safe copy storage in case of overwriting.
105→	c.storage.Range(func(k, v interface{}) bool {
106→		copy.storage.Store(k, v.(fwk.StateData).Clone())
107→		return true
108→	})
109→	// The below are not mutated, so we don't have to safe copy.
110→	copy.recordPluginMetrics = c.recordPluginMetrics
111→	copy.skipFilterPlugins = c.skipFilterPlugins
112→	copy.skipScorePlugins = c.skipScorePlugins
113→	copy.skipPreBindPlugins = c.skipPreBindPlugins
114→	copy.parallelPreBindPlugins = c.parallelPreBindPlugins
115→
116→	return copy
117→}
118→
119→// Read retrieves data with the given "key" from CycleState. If the key is not
120→// present, ErrNotFound is returned.
121→//
122→// See CycleState for notes on concurrency.
123→func (c *CycleState) Read(key fwk.StateKey) (fwk.StateData, error) {
124→	if v, ok := c.storage.Load(key); ok {
125→		return v.(fwk.StateData), nil
126→	}
127→	return nil, fwk.ErrNotFound
128→}
129→
130→// Write stores the given "val" in CycleState with the given "key".
131→//
132→// See CycleState for notes on concurrency.
133→func (c *CycleState) Write(key fwk.StateKey, val fwk.StateData) {
134→	c.storage.Store(key, val)
135→}
136→
137→// Delete deletes data with the given key from CycleState.
138→//
139→// See CycleState for notes on concurrency.
140→func (c *CycleState) Delete(key fwk.StateKey) {
141→	c.storage.Delete(key)
142→}
